  constructor(
    readonly slot: ModelSlot,
    readonly modelId: string,
    readonly missing: string[],
  ) {
    super(
      `Model ${modelId} is not valid for ${slot}; missing required capability${
        missing.length === 1 ? '' : 'ies'
