      return {
        id: 'chatcmpl_test',
        choices: [{ message: { content: '{"value":"ok"}' }, finish_reason: 'stop' }],
        usage: { prompt_tokens: 1, completion_tokens: 1, prompt_cache_hit_tokens: 0 },
      };
